import 'package:build/build.dart' hide Builder;
import 'package:built_collection/built_collection.dart';
import 'package:built_value/built_value.dart';
import 'package:dart_style/dart_style.dart';
import 'package:path/path.dart' as p;

import 'br_outputs.dart';

part 'shared_part.g.dart';

/// A part file generated by `LibrarySourceSink` which may be appended to by
/// multiple builders sequentially.
abstract class SharedPart implements Built<SharedPart, SharedPartBuilder> {
  /// The [AssetId] of the library that this part belongs to.
  AssetId get primaryInput;

  /// The imports required by each builder phase.
  BuiltMap<int, BuiltList<String>> get imports;

  /// The source code contributions from each builder phase.
  BuiltMap<int, String> get contributions;

  /// The Dart language version extracted from the file (if any).
  String? get languageVersion;

  SharedPart._();

  factory SharedPart([void Function(SharedPartBuilder) updates]) = _$SharedPart;

  /// Generates the `part of` directive connecting this part to the primary
  /// library.
  String get partOfDirective {
    final relativePath = p.url.relative(
      primaryInput.path,
      from: p.url.dirname(primaryInput.brOutputIdForPrimaryInput.path),
    );
    return "part of '$relativePath';";
  }

  /// Converts this [SharedPart] into the final source code to be written to
  /// disk.
  String generateContent({bool format = true}) {
    final validPhases = <int>{...imports.keys, ...contributions.keys}.toList();
    validPhases.sort();

    final buffer = StringBuffer();
    if (languageVersion != null) {
      buffer.writeln(languageVersion);
    }
    buffer.writeln(partOfDirective);
    buffer.writeln();

    for (final phase in validPhases) {
      if (imports[phase]?.isNotEmpty ?? false) {
        buffer.writeln('// @PartBuilder:imports:$phase');
        for (final import in imports[phase]!) {
          buffer.writeln(import);
        }
      }
    }
    buffer.writeln();

    for (final phase in validPhases) {
      if (contributions[phase] != null) {
        buffer.writeln('// @PartBuilder:contribution:$phase');
        buffer.writeln(contributions[phase]);
        buffer.writeln();
      }
    }

    final rawContent = buffer.toString();
    String formattedContent;
    if (format) {
      try {
        formattedContent = DartFormatter(
          languageVersion: DartFormatter.latestLanguageVersion,
        ).format(rawContent);
      } catch (_) {
        formattedContent = rawContent;
      }
    } else {
      formattedContent = rawContent;
    }

    if (languageVersion != null) {
      return formattedContent.replaceFirst(
        languageVersion!,
        '$languageVersion\n// dart format off',
      );
    } else {
      return '// dart format off\n$formattedContent';
    }
  }

  /// Parses the raw content of a shared part file on disk into a [SharedPart].
  static SharedPart parseContent(String content, AssetId primaryInput) {
    if (content.isEmpty) {
      return SharedPart((b) => b..primaryInput = primaryInput);
    }

    final importPattern = RegExp(r'^// @PartBuilder:imports:(\d+)$');
    final contributionPattern = RegExp(r'^// @PartBuilder:contribution:(\d+)$');

    final lines = content.split('\n');
    var currentPhase = -1;
    var isImport = false;
    String? parsedLanguageVersion;

    if (lines.isNotEmpty && lines.first.startsWith('// @dart=')) {
      parsedLanguageVersion = lines.first;
    }

    final importsByPhase = <int, List<String>>{};
    final contributionsByPhase = <int, StringBuffer>{};

    for (final line in lines) {
      final importMatch = importPattern.firstMatch(line);
      if (importMatch != null) {
        currentPhase = int.parse(importMatch.group(1)!);
        isImport = true;
        continue;
      }
      final contributionMatch = contributionPattern.firstMatch(line);
      if (contributionMatch != null) {
        currentPhase = int.parse(contributionMatch.group(1)!);
        isImport = false;
        continue;
      }

      if (currentPhase != -1) {
        if (isImport) {
          if (line.isNotEmpty) {
            importsByPhase.putIfAbsent(currentPhase, () => []).add(line);
          }
        } else {
          final buf = contributionsByPhase.putIfAbsent(
            currentPhase,
            StringBuffer.new,
          );
          if (buf.isNotEmpty) buf.writeln();
          buf.write(line);
        }
      }
    }

    return SharedPart((b) {
      b.primaryInput = primaryInput;
      b.languageVersion = parsedLanguageVersion;
      importsByPhase.forEach((phase, list) {
        b.imports[phase] = BuiltList<String>(list);
      });
      contributionsByPhase.forEach((phase, buf) {
        b.contributions[phase] = buf.toString().trimRight();
      });
    });
  }
}
